insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('83921304-c871-5617-bb28-3ab87f6c2e91', '6cca8cda-e3b2-5db0-8cba-37d2d291c067', '4124c457-9768-5401-ad8a-2cbe8827e05c', 'situation', '{"body":"Kai just did the impossible again — shipped a six-month integration in nine days, personally, mostly overnight, and landed Anderson: the biggest logo in company history. The board wants the hero on stage. How you celebrate this teaches the whole company what earns status at Lumen.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
