insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0d80c233-b48d-5e0d-bc7b-0ad8c5289b06', '6cca8cda-e3b2-5db0-8cba-37d2d291c067', '4124c457-9768-5401-ad8a-2cbe8827e05c', 'message', '{"body":"Put Kai on stage at the all-hands. Reward the outcome loudly. That’s the culture I want new hires to see on day one.","from":"board"}'::jsonb, 14, '{"week":2,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
