insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c08480ef-bb63-55d0-83d5-1f95aa027bc4', '6cca8cda-e3b2-5db0-8cba-37d2d291c067', '4124c457-9768-5401-ad8a-2cbe8827e05c', 'message', '{"body":"For the record, I don’t need the stage. Just don’t undercut the biggest win in company history with a “but.”","from":"kai"}'::jsonb, 17, '{"week":2,"from":"kai","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9848a2c5-8b62-509d-9d63-012dd6c61572', '6cca8cda-e3b2-5db0-8cba-37d2d291c067', '4124c457-9768-5401-ad8a-2cbe8827e05c', 'situation', '{"body":"Priya: one of the two engineers on the Anderson push just declined the retention grant we auto-offered. In my experience that means they already have something else in hand. Thought you’d want to know before the celebration, not after.","from":"cfo"}'::jsonb, 18, '{"week":2,"from":"cfo","beat":"surprise","day":4,"kind":"signal","title":"A quiet flag on retention"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
