insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('574cddfd-391d-5fc1-88ee-9f5f6b4e2feb', '6cca8cda-e3b2-5db0-8cba-37d2d291c067', '4124c457-9768-5401-ad8a-2cbe8827e05c', 'message', '{"body":"I don’t understand. I gave this everything. Was it me? I need you to actually tell me the truth for once.","from":"kai"}'::jsonb, 51, '{"week":4,"from":"kai","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"backed"}'::jsonb) on conflict (id) do update set seat_id = excluded.seat_id, kind = excluded.kind, payload_json = excluded.payload_json, order_idx = excluded.order_idx, trigger_json = excluded.trigger_json;
